import * as AasTypes from "../src/types";
import * as AasVerification from "../src/verification";

test("verification path and segments format", () => {
  const path = new AasVerification.Path();

  path.prepend(
    new AasVerification.IndexSegment(
      <Array<AasTypes.Class>>[],
      2
    )
  );
  path.prepend(
    new AasVerification.PropertySegment(
      <AasTypes.Class>{},
      "something"
    )
  );

  expect(path.toString()).toStrictEqual(".something[2]");
});

test("verification error stores provided path", () => {
  const path = new AasVerification.Path();
  path.prepend(
    new AasVerification.PropertySegment(
      <AasTypes.Class>{},
      "idShort"
    )
  );

  const error = new AasVerification.VerificationError(
    "Some verification error",
    path
  );

  expect(error.message).toStrictEqual("Some verification error");
  expect(error.path.toString()).toStrictEqual(".idShort");
});

